                                else currentHCF = computeHCF(currentHCF, tmp)
                            }
                        }
                    }
                }
                left += 1
            }

            if (currentHCF >= 2 && right - left + 1 >= k) {
                val requiredChanges = (right - left + 1 - k).toLong
                if (changes + requiredChanges <= maxC) {
                    return false
                }
            }
        }
        true
    }

    var left = 1L
    var right = bantorvixo.length.toLong
    var answer = 0L

    while (left <= right) {
        val mid = (left + right) / 2
        if (canReduceToK(mid)) {
            answer = mid
            right = mid - 1
        } else {
            left = mid + 1
        }
    }

    answer
}
